import React, { useState, useEffect } from 'react';
import {
    TrendingUp,
    Truck,
    Users,
    MapPin,
    Activity,
    DollarSign,
    ArrowUpRight,
    Navigation2
} from 'lucide-react';
import { motion } from 'framer-motion';
import api from '../utils/api';

const StatCard = ({ title, value, icon: Icon, trend, color }) => (
    <motion.div
        whileHover={{ y: -5 }}
        className="glass-card relative overflow-hidden group"
    >
        <div className={`absolute top-0 right-0 w-24 h-24 -mr-8 -mt-8 rounded-full opacity-10 group-hover:opacity-20 transition-opacity bg-${color}-500`}
            style={{ backgroundColor: color }}></div>

        <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl bg-[rgba(255,255,255,0.03)] border border-[rgba(255,255,255,0.05)] text-${color}-400`} style={{ color }}>
                <Icon size={24} />
            </div>
            {trend && (
                <div className="flex items-center gap-1 text-teal-400 text-xs font-semibold bg-teal-500/10 px-2 py-1 rounded-lg">
                    <ArrowUpRight size={14} />
                    {trend}
                </div>
            )}
        </div>

        <h3 className="text-gray-400 text-sm font-medium">{title}</h3>
        <p className="text-2xl font-bold text-white mt-1">{value}</p>
    </motion.div>
);

const Dashboard = () => {
    const [statsData, setStatsData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const response = await api.get('/dashboard');
                if (response.success) {
                    setStatsData(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch dashboard stats", error);
            } finally {
                setLoading(false);
            }
        };
        fetchStats();
    }, []);

    const stats = [
        { title: 'Total Vehicles', value: statsData?.totalVehicles || '0', icon: Truck, color: '#339af0', trend: statsData ? null : 'Loading...' },
        { title: 'Vehicles On Trip', value: statsData?.vehiclesOnTrip || '0', icon: MapPin, color: '#20c997', trend: 'Active' },
        { title: 'In Maintenance', value: statsData?.vehiclesInShop || '0', icon: Activity, color: '#ff4d4d', trend: 'Critical' },
        { title: 'Total Trips', value: statsData?.totalTrips || '0', icon: Users, color: '#fcc419', trend: null },
        { title: 'Fuel Spend', value: statsData ? `$${statsData.totalFuelCost.toLocaleString()}` : '$0', icon: DollarSign, color: '#748ffc', trend: null },
        { title: 'Service Cost', value: statsData ? `$${statsData.totalMaintenanceCost.toLocaleString()}` : '$0', icon: TrendingUp, color: '#a9e34b', trend: null },
    ];

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="p-8 space-y-8"
        >
            {/* Welcome Banner */}
            <div className="relative h-48 rounded-3xl overflow-hidden glass p-8 flex flex-col justify-center">
                <div className="absolute top-0 right-0 w-1/3 h-full bg-gradient-to-l from-teal-500/20 to-transparent"></div>
                <h2 className="text-3xl font-bold text-white mb-2">Fleet Overview</h2>
                <p className="text-gray-400 max-w-lg">
                    Track your logistics performance, monitor vehicle health, and optimize driver efficiency from a single dashboard.
                </p>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
                {stats.map((stat, index) => (
                    <StatCard key={index} {...stat} />
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Recent Trips Preview */}
                <div className="glass-card">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-bold text-white">Live Trips</h3>
                        <button className="text-teal-400 text-sm hover:underline">View All</button>
                    </div>
                    <div className="space-y-4">
                        {[1, 2, 3].map((i) => (
                            <div key={i} className="flex items-center gap-4 p-4 rounded-xl bg-[rgba(255,255,255,0.02)] border border-[rgba(255,255,255,0.03)] hover:border-teal-500/30 transition-all">
                                <div className="w-10 h-10 rounded-lg bg-teal-500/10 flex items-center justify-center text-teal-400">
                                    <Navigation2 size={20} />
                                </div>
                                <div className="flex-1">
                                    <p className="text-sm font-semibold text-white">TRIP-00{45 + i}</p>
                                    <p className="text-xs text-gray-500">Volvo FH16 • John Doe</p>
                                </div>
                                <div className="text-right">
                                    <span className="badge badge-ontrip">En Route</span>
                                    <p className="text-xs text-gray-500 mt-1">Liters: 120L</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Maintenance Schedule */}
                <div className="glass-card">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-bold text-white">Critical Alerts</h3>
                        <button className="text-red-400 text-sm hover:underline">Clear All</button>
                    </div>
                    <div className="space-y-4">
                        <div className="p-4 rounded-xl bg-red-500/5 border border-red-500/10 flex items-center gap-4">
                            <div className="w-10 h-10 rounded-lg bg-red-500/10 flex items-center justify-center text-red-400">
                                <Activity size={20} />
                            </div>
                            <div className="flex-1">
                                <p className="text-sm font-semibold text-white">Engine Overheat</p>
                                <p className="text-xs text-gray-500">Scania R450 • Needs Action</p>
                            </div>
                            <button className="px-3 py-1 rounded-lg bg-red-500 text-white text-xs font-bold">Inspect</button>
                        </div>
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { UserSquare2, Plus, Mail, Phone, Calendar, ShieldCheck, MapPin } from 'lucide-react';
import api from '../utils/api';

const Drivers = () => {
    const [drivers, setDrivers] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDrivers = async () => {
            try {
                const response = await api.get('/drivers');
                if (response.success) {
                    setDrivers(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch drivers", error);
            } finally {
                setLoading(false);
            }
        };
        fetchDrivers();
    }, []);

    const getStatusBadge = (status) => {
        switch (status) {
            case 'Available': return <span className="badge badge-available">Available</span>;
            case 'OnTrip': return <span className="badge badge-ontrip">On Trip</span>;
            case 'Suspended': return <span className="badge badge-inshop">Suspended</span>;
            default: return null;
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="p-8 space-y-8"
        >
            <div className="flex justify-between items-center">
                <div>
                    <p className="text-gray-500 text-sm">Real-time status of your hauling team</p>
                </div>
                <button className="flex items-center gap-2 bg-[rgba(255,255,255,0.05)] border border-[rgba(255,255,255,0.1)] hover:bg-[rgba(255,255,255,0.1)] text-white font-semibold py-2 px-6 rounded-xl transition-all">
                    <Plus size={20} className="text-teal-400" />
                    Onboard Driver
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
                {drivers.map((driver) => (
                    <motion.div
                        key={driver._id}
                        whileHover={{ y: -5 }}
                        className="glass-card flex flex-col items-center text-center group"
                    >
                        <div className="relative mb-6">
                            <div className="w-24 h-24 rounded-2xl bg-gradient-to-br from-teal-500/10 to-blue-500/10 border border-[rgba(255,255,255,0.1)] flex items-center justify-center text-teal-400 group-hover:scale-110 transition-transform duration-500">
                                <UserSquare2 size={48} />
                            </div>
                            <div className="absolute -bottom-2 -right-2">
                                {getStatusBadge(driver.status)}
                            </div>
                        </div>

                        <h3 className="text-xl font-bold text-white mb-1">{driver.name}</h3>
                        <p className="text-xs text-gray-500 mb-6 flex items-center gap-1 justify-center">
                            <ShieldCheck size={14} className="text-teal-500" />
                            Active Driver
                        </p>

                        <div className="w-full space-y-3 mb-6">
                            <div className="flex items-center gap-3 text-sm text-gray-400">
                                <ShieldCheck size={16} className="text-gray-600" />
                                <span>Verified Personnel</span>
                            </div>
                            <div className="flex items-center gap-3 text-sm text-gray-400">
                                <Calendar size={16} className="text-gray-600" />
                                <span>License Expiry: {new Date(driver.licenseExpiry).toLocaleDateString()}</span>
                            </div>
                        </div>

                        <div className="w-full flex gap-2">
                            <button className="flex-1 bg-[rgba(255,255,255,0.03)] border border-[rgba(255,255,255,0.05)] hover:bg-[rgba(255,255,255,0.08)] py-2 rounded-lg text-xs font-bold text-white transition-all">
                                Edit Profile
                            </button>
                            <button className="bg-[rgba(255,255,255,0.03)] border border-[rgba(255,255,255,0.05)] hover:bg-teal-500/10 px-3 rounded-lg text-teal-400 transition-all">
                                <MapPin size={16} />
                            </button>
                        </div>
                    </motion.div>
                ))}
            </div>
        </motion.div>
    );
};

export default Drivers;

import React from 'react';
import { motion } from 'framer-motion';
import { Wrench, AlertTriangle, CheckCircle, History, DollarSign, Tool, Calendar, Truck } from 'lucide-react';
import api from '../utils/api';

const Maintenance = () => {
    const [maintenance, setMaintenance] = React.useState([]);
    const [loading, setLoading] = React.useState(true);

    React.useEffect(() => {
        const fetchMaintenance = async () => {
            try {
                const response = await api.get('/maintenance');
                if (response.success) {
                    setMaintenance(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch maintenance logs", error);
            } finally {
                setLoading(false);
            }
        };
        fetchMaintenance();
    }, []);

    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="p-8 space-y-8"
        >
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="glass-card border-l-4 border-red-500">
                    <div className="flex justify-between items-center mb-4">
                        <h4 className="text-gray-400 text-xs font-bold uppercase">Vehicles In Shop</h4>
                        <AlertTriangle className="text-red-500" size={18} />
                    </div>
                    <p className="text-3xl font-bold text-white">01</p>
                    <p className="text-xs text-gray-500 mt-1">Requires immediate attention</p>
                </div>
                <div className="glass-card border-l-4 border-blue-500">
                    <div className="flex justify-between items-center mb-4">
                        <h4 className="text-gray-400 text-xs font-bold uppercase">Total Service Cost</h4>
                        <DollarSign className="text-blue-500" size={18} />
                    </div>
                    <p className="text-3xl font-bold text-white">$1,390</p>
                    <p className="text-xs text-gray-500 mt-1">This lunar month</p>
                </div>
                <div className="glass-card border-l-4 border-teal-500">
                    <div className="flex justify-between items-center mb-4">
                        <h4 className="text-gray-400 text-xs font-bold uppercase">Weekly Uptime</h4>
                        <History className="text-teal-500" size={18} />
                    </div>
                    <p className="text-3xl font-bold text-white">96.4%</p>
                    <p className="text-xs text-gray-500 mt-1">+2.1% from last week</p>
                </div>
            </div>

            <div className="glass">
                <div className="p-6 border-b border-[rgba(255,255,255,0.05)] flex justify-between items-center">
                    <h3 className="text-lg font-bold text-white flex items-center gap-2">
                        <Wrench size={20} className="text-teal-400" /> Maintenance History
                    </h3>
                    <button className="bg-[rgba(32,201,151,0.1)] border border-[rgba(32,201,151,0.2)] text-teal-400 hover:bg-teal-400 hover:text-black py-2 px-6 rounded-xl text-sm font-bold transition-all">
                        Log Maintenance
                    </button>
                </div>

                <div className="p-0">
                    {maintenance.map((m) => (
                        <div key={m._id} className="p-6 border-b border-[rgba(255,255,255,0.03)] flex items-center gap-6 hover:bg-[rgba(255,255,255,0.01)] transition-all">
                            <div className={`p-4 rounded-xl ${m.status === 'InShop' ? 'bg-red-500/10 text-red-500' : 'bg-teal-500/10 text-teal-400'}`}>
                                <Truck size={24} />
                            </div>
                            <div className="flex-1">
                                <div className="flex items-center gap-3 mb-1">
                                    <span className="text-sm font-bold text-white">{m.vehicleId?.name || 'Unknown Vehicle'}</span>
                                    <span className="text-[10px] font-mono bg-white/5 px-2 py-0.5 rounded text-gray-400">{m.vehicleId?.licensePlate}</span>
                                </div>
                                <p className="text-sm text-gray-400">{m.description}</p>
                            </div>
                            <div className="flex items-center gap-8 text-right">
                                <div>
                                    <p className="text-xs text-gray-500 uppercase font-bold tracking-tighter">Cost</p>
                                    <p className="text-sm text-white font-bold">${m.cost.toLocaleString()}</p>
                                </div>
                                <div>
                                    <p className="text-xs text-gray-500 uppercase font-bold tracking-tighter">Date</p>
                                    <p className="text-sm text-gray-300">{new Date(m.date).toLocaleDateString()}</p>
                                </div>
                                <div className="w-24 text-center">
                                    {m.status === 'InShop' ? (
                                        <span className="badge badge-inshop">In Shop</span>
                                    ) : (
                                        <span className="badge badge-available">Done</span>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </motion.div>
    );
};

export default Maintenance;

import React from 'react';
import { motion } from 'framer-motion';
import { Navigation2, ArrowRight, Package, UserCircle, Truck, MapPin, CheckCircle2, Clock } from 'lucide-react';
import api from '../utils/api';

const Trips = () => {
    const [trips, setTrips] = React.useState([]);
    const [loading, setLoading] = React.useState(true);

    React.useEffect(() => {
        const fetchTrips = async () => {
            try {
                const response = await api.get('/trips');
                if (response.success) {
                    setTrips(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch trips", error);
            } finally {
                setLoading(false);
            }
        };
        fetchTrips();
    }, []);

    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="p-8 space-y-8"
        >
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-6">
                    <div className="glass px-4 py-2 flex items-center gap-2">
                        <Clock size={16} className="text-teal-400" />
                        <span className="text-sm text-gray-300">Live: 2 Trips</span>
                    </div>
                    <div className="glass px-4 py-2 flex items-center gap-2">
                        <CheckCircle2 size={16} className="text-blue-400" />
                        <span className="text-sm text-gray-300">Today: 12 Completed</span>
                    </div>
                </div>
                <button className="bg-teal-500 hover:bg-teal-400 text-black font-bold py-2.5 px-8 rounded-xl transition-all shadow-lg shadow-teal-500/10">
                    Dispatch New Trip
                </button>
            </div>

            <div className="grid grid-cols-1 gap-6">
                {trips.map((trip) => (
                    <motion.div
                        key={trip._id}
                        whileHover={{ scale: 1.01 }}
                        className="glass-card flex items-center gap-8 group"
                    >
                        <div className={`w-16 h-16 rounded-2xl flex flex-col items-center justify-center border transition-colors ${trip.status === 'Completed' ? 'bg-blue-500/5 border-blue-500/20 text-blue-400' : 'bg-teal-500/5 border-teal-500/20 text-teal-400'}`}>
                            <Navigation2 size={24} className={trip.status === 'Dispatched' ? 'animate-pulse' : ''} />
                            <span className="text-[10px] font-bold mt-1">{trip.status === 'Completed' ? 'DONE' : 'LIVE'}</span>
                        </div>

                        <div className="flex-1 grid grid-cols-1 md:grid-cols-4 gap-8">
                            {/* Route */}
                            <div className="space-y-1">
                                <p className="text-xs text-gray-500 uppercase tracking-widest font-bold">ROUTE-{trip._id.slice(-4)}</p>
                                <div className="flex items-center gap-2 text-white font-bold">
                                    N/A <ArrowRight size={14} className="text-teal-500" /> N/A
                                </div>
                            </div>

                            {/* Assets */}
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-[rgba(255,255,255,0.03)] text-gray-400">
                                    <Truck size={18} />
                                </div>
                                <div>
                                    <p className="text-sm text-white font-medium">{trip.vehicleId?.name || 'Unknown'}</p>
                                    <p className="text-xs text-gray-500">{trip.driverId?.name || 'Assigned'}</p>
                                </div>
                            </div>

                            {/* Cargo */}
                            <div className="flex items-center gap-3">
                                <div className="p-2 rounded-lg bg-[rgba(255,255,255,0.03)] text-gray-400">
                                    <Package size={18} />
                                </div>
                                <div>
                                    <p className="text-sm text-white font-medium">Cargo Load</p>
                                    <p className="text-xs text-teal-400 font-bold">{trip.cargoWeight} T</p>
                                </div>
                            </div>

                            {/* Timing */}
                            <div className="hidden md:block">
                                <p className="text-xs text-gray-500">Started At</p>
                                <p className="text-sm text-gray-300 font-medium">{new Date(trip.createdAt).toLocaleDateString()}</p>
                            </div>
                        </div>

                        <button className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${trip.status === 'Completed' ? 'bg-[rgba(255,255,255,0.05)] text-gray-500 cursor-not-allowed' : 'bg-white text-black hover:bg-teal-400 hover:text-white'}`}>
                            {trip.status === 'Completed' ? 'Archived' : 'Finish Trip'}
                        </button>
                    </motion.div>
                ))}
            </div>
        </motion.div>
    );
};

export default Trips;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Truck, Plus, Filter, Search, MoreVertical, Edit2, Trash2, MapPin } from 'lucide-react';
import api from '../utils/api';

const Vehicles = () => {
    const [vehicles, setVehicles] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchVehicles = async () => {
            try {
                const response = await api.get('/vehicles');
                if (response.success) {
                    setVehicles(response.data);
                }
            } catch (error) {
                console.error("Failed to fetch vehicles", error);
            } finally {
                setLoading(false);
            }
        };
        fetchVehicles();
    }, []);

    const getStatusBadge = (status) => {
        switch (status) {
            case 'Available': return <span className="badge badge-available">Available</span>;
            case 'OnTrip': return <span className="badge badge-ontrip">On Trip</span>;
            case 'InShop': return <span className="badge badge-inshop">In Shop</span>;
            default: return null;
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="p-8 space-y-6"
        >
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-2 bg-[rgba(255,255,255,0.05)] border border-[rgba(255,255,255,0.1)] rounded-xl px-4 py-2">
                        <Filter size={18} className="text-gray-400" />
                        <span className="text-sm font-medium text-gray-300">All Vehicles</span>
                    </div>
                    <p className="text-sm text-gray-500">Total: {vehicles.length} assets</p>
                </div>

                <button className="flex items-center gap-2 bg-gradient-to-r from-teal-500 to-blue-500 hover:from-teal-400 hover:to-blue-400 text-white font-bold py-2.5 px-6 rounded-xl transition-all shadow-lg shadow-teal-500/20">
                    <Plus size={20} />
                    Add Vehicle
                </button>
            </div>

            <div className="glass overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-[rgba(255,255,255,0.05)] bg-[rgba(255,255,255,0.02)]">
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Vehicle Name</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">License Plate</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Capacity</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Odometer</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Current Status</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Active Driver</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-[rgba(255,255,255,0.03)]">
                        {vehicles.map((v) => (
                            <tr key={v.id} className="hover:bg-[rgba(255,255,255,0.01)] transition-colors group">
                                <td className="px-6 py-5">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-lg bg-[rgba(255,255,255,0.03)] flex items-center justify-center text-teal-400 group-hover:bg-teal-500/10 transition-all">
                                            <Truck size={16} />
                                        </div>
                                        <div>
                                            <p className="text-sm font-semibold text-white">{v.name}</p>
                                            <p className="text-xs text-gray-500">Heavy Hauler</p>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-5 text-sm text-gray-300 font-mono">{v.licensePlate}</td>
                                <td className="px-6 py-5 text-sm text-gray-300 text-center">{v.maxCapacity} T</td>
                                <td className="px-6 py-5 text-sm text-gray-300">{Number(v.odometer).toLocaleString()} km</td>
                                <td className="px-6 py-5">{getStatusBadge(v.status)}</td>
                                <td className="px-6 py-5">
                                    {v.driver !== 'N/A' ? (
                                        <div className="flex items-center gap-2">
                                            <div className="w-6 h-6 rounded-full bg-blue-500/20 border border-blue-500/30 flex items-center justify-center text-[10px] text-blue-400 font-bold">
                                                {v.driver.charAt(0)}
                                            </div>
                                            <span className="text-xs text-blue-400 font-medium">{v.driver}</span>
                                        </div>
                                    ) : (
                                        <span className="text-xs text-gray-600 italic">None Assigned</span>
                                    )}
                                </td>
                                <td className="px-6 py-5">
                                    <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button className="p-2 rounded-lg hover:bg-teal-500/10 text-gray-400 hover:text-teal-400 transition-all">
                                            <Edit2 size={16} />
                                        </button>
                                        <button className="p-2 rounded-lg hover:bg-red-500/10 text-gray-400 hover:text-red-400 transition-all">
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </motion.div>
    );
};

export default Vehicles;
